<template><div class="page-container"><el-card><template #header><div class="card-header"><span>费用管理</span><el-button type="primary" size="small">添加费用单</el-button></div></template><el-form :inline="true"><el-form-item label="状态"><el-select v-model="f.status" clearable><el-option v-for="s in ['DRAFT','PROCESSING','COMPLETED']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="费用单号" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="order_no" label="费用单号" width="150"/><el-table-column prop="expense_type_id" label="费用类型" width="100"/><el-table-column prop="amount" label="金额" width="120"/><el-table-column prop="currency" label="币种" width="80"/><el-table-column prop="allocation_method" label="分摊方式" width="100"/><el-table-column prop="allocation_dimension" label="分摊维度" width="100"/><el-table-column prop="status" label="状态" width="100"/><el-table-column prop="created_at" label="创建时间" width="160"/></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { getExpenseOrders } from '@/api/finance'
const f = reactive({ status: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await getExpenseOrders({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
onMounted(load)
</script>
